import js from '@eslint/js'
import globals from 'globals'
import reactHooks from 'eslint-plugin-react-hooks'
import reactRefresh from 'eslint-plugin-react-refresh'
import tseslint from 'typescript-eslint'
import prettier from 'eslint-config-prettier'
import noRawGraphqlStrings from './eslint-rules/no-raw-graphql-strings.js'

export default tseslint.config(
  { ignores: ['dist', 'node_modules', 'storybook-static'] },
  {
    extends: [js.configs.recommended, ...tseslint.configs.recommended],
    files: ['**/*.{ts,tsx}'],
    languageOptions: {
      ecmaVersion: 2020,
      globals: globals.browser,
    },
    plugins: {
      'react-hooks': reactHooks,
      'react-refresh': reactRefresh,
      'kapow': { rules: { 'no-raw-graphql-strings': noRawGraphqlStrings } },
    },
    rules: {
      ...reactHooks.configs.recommended.rules,
      'react-refresh/only-export-components': [
        'warn',
        { allowConstantExport: true },
      ],
      'kapow/no-raw-graphql-strings': 'error',
    },
  },
  // shadcn/ui components export variant helpers alongside components — silence fast-refresh warning
  {
    files: ['src/components/ui/**/*.{ts,tsx}'],
    rules: {
      'react-refresh/only-export-components': 'off',
    },
  },
  // Search shared components export types, helpers, and components from the same barrel
  {
    files: ['src/components/search/**/*.{ts,tsx}'],
    rules: {
      'react-refresh/only-export-components': 'off',
    },
  },
  // Story files export a default meta + named story objects — silence fast-refresh warning
  {
    files: ['src/**/*.stories.@(ts|tsx)'],
    rules: {
      'react-refresh/only-export-components': 'off',
    },
  },
  // Type augmentation files use empty interface extension by design
  {
    files: ['src/test/**/*.d.ts'],
    rules: {
      '@typescript-eslint/no-empty-object-type': 'off',
    },
  },
  prettier,
)

