import { Routes, Route } from 'react-router-dom'
import { Header } from '@/components/layout/Header'
import { Footer } from '@/components/layout/Footer'
import { useWebMCP } from '@/hooks/useWebMCP'
import { useAuthStore } from '@/stores/authStore'
import { usePreferencesStore } from '@/stores/preferencesStore'
import { About } from '@/pages/About'
import { AuthCallback } from '@/pages/AuthCallback'
import { Home } from '@/pages/Home'
import { Search } from '@/pages/Search'

export function App() {
  useWebMCP()

  const initialize = useAuthStore((s) => s.initialize)
  const session = useAuthStore((s) => s.session)
  const loadPreferences = usePreferencesStore((s) => s.load)
  const clearPreferences = usePreferencesStore((s) => s.clear)

  useEffect(() => {
    initialize()
  }, [initialize])

  useEffect(() => {
    if (session) {
      loadPreferences()
    } else {
      clearPreferences()
    }
  }, [session, loadPreferences, clearPreferences])

  return (
    <div style={{ display: 'flex', minHeight: '100vh', flexDirection: 'column' }}>
      <Header />
      <Routes>
        <Route path="/" element={<Home />} />
        <Route path="/about" element={<About />} />
        <Route path="/auth/callback" element={<AuthCallback />} />
        <Route path="/search" element={<Search />} />
      </Routes>
      <Footer />
    </div>
  )
}

/**
 * Strict GraphQL utilities — re-exports urql hooks with types that reject raw strings.
 *
 * Import useQuery/useMutation from here instead of 'urql'. Raw string queries
 * bypass gql.tada's compile-time schema validation, which has caused production
 * bugs (e.g. querying fields that don't exist in the schema).
 *
 * These wrappers require a parsed DocumentNode (has 'kind' and 'definitions'),
 * which gql.tada's graphql() returns but raw strings do not satisfy.
 *
 * Usage:
 *   import { graphql } from 'gql.tada'
 *   import { useQuery, useMutation } from '@/lib/graphql'
 *
 *   const MyQuery = graphql(`query MyQuery { ... }`)
 *   const [result] = useQuery({ query: MyQuery })
 */

import {
  useQuery as _useQuery,
  useMutation as _useMutation,
  type UseQueryResponse,
  type UseMutationResponse,
  type AnyVariables,
  type OperationContext,
  type RequestPolicy,
} from 'urql'

// A parsed GraphQL document has { kind: 'Document', definitions: [...] }.
// gql.tada's graphql() returns this at runtime. Raw strings don't have these
// properties, so TypeScript rejects them.
interface ParsedDocument {
  readonly kind: string
  readonly definitions: readonly unknown[]
}

interface StrictQueryArgs<Variables extends AnyVariables = AnyVariables> {
  query: ParsedDocument
  variables?: Variables
  requestPolicy?: RequestPolicy
  context?: Partial<OperationContext>
  pause?: boolean
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
export function useQuery<Data = any, Variables extends AnyVariables = AnyVariables>(
  args: StrictQueryArgs<Variables>,
): UseQueryResponse<Data, Variables> {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  return _useQuery(args as any)
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
export function useMutation<Data = any, Variables extends AnyVariables = AnyVariables>(
  query: ParsedDocument,
): UseMutationResponse<Data, Variables> {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  return _useMutation(query as any)
}

import { Client, cacheExchange, fetchExchange } from 'urql'
import { authExchange } from '@urql/exchange-auth'
import { useAuthStore } from '@/stores/authStore'
import { supabase } from './supabase'

export const urqlClient = new Client({
  url: '/graphql',
  exchanges: [
    cacheExchange,
    authExchange(async (utils) => ({
      addAuthToOperation(operation) {
        const token = useAuthStore.getState().getToken()
        if (!token) return operation
        return utils.appendHeaders(operation, {
          Authorization: `Bearer ${token}`,
        })
      },
      didAuthError(error) {
        return error.graphQLErrors.some(
          (e) => e.extensions?.code === 'FORBIDDEN' || e.extensions?.code === 'UNAUTHENTICATED',
        ) || error.response?.status === 401
      },
      async refreshAuth() {
        const { data } = await supabase.auth.getSession()
        useAuthStore.getState().setSession(data.session)
      },
    })),
    fetchExchange,
  ],
})

import { create } from 'zustand'
import type { Session, User, AuthChangeEvent } from '@supabase/supabase-js'
import { supabase } from '@/lib/supabase'

interface AuthState {
  session: Session | null
  user: User | null
  loading: boolean

  initialize: () => Promise<void>
  setSession: (session: Session | null) => void
  signOut: () => Promise<void>
  getToken: () => string | undefined
}

export const useAuthStore = create<AuthState>()((set, get) => ({
  session: null,
  user: null,
  loading: true,

  initialize: async () => {
    const {
      data: { session },
    } = await supabase.auth.getSession()
    set({ session, user: session?.user ?? null, loading: false })

    supabase.auth.onAuthStateChange(
      (_event: AuthChangeEvent, session: Session | null) => {
        set({ session, user: session?.user ?? null })
      },
    )
  },

  setSession: (session: Session | null) => {
    set({ session, user: session?.user ?? null })
  },

  signOut: async () => {
    await supabase.auth.signOut()
    set({ session: null, user: null })
  },

  getToken: () => {
    return get().session?.access_token
  },
}))

import { render, type RenderOptions } from '@testing-library/react'
import { MantineProvider } from '@mantine/core'
import { theme } from '../theme'

/** Wraps component in MantineProvider for tests that use Mantine components. */
export function renderWithMantine(ui: React.ReactElement, options?: RenderOptions) {
  return render(ui, {
    wrapper: ({ children }) => <MantineProvider theme={theme}>{children}</MantineProvider>,
    ...options,
  })
}

import * as matchers from '@testing-library/jest-dom/matchers'
import { expect, afterEach } from 'vitest'
import { cleanup } from '@testing-library/react'

expect.extend(matchers)

// Cleanup DOM after each test (required when not using vitest globals)
afterEach(() => {
  cleanup()
})

/**
 * ESLint rule: no-raw-graphql-strings
 *
 * Prevents raw template-literal or string-literal GraphQL queries.
 * All queries must use graphql() from gql.tada for compile-time schema validation.
 *
 * Flags template literals and string literals whose content starts with
 * "query ", "mutation ", "subscription ", or "fragment " (after trimming).
 *
 * Allows:
 *   import { graphql } from 'gql.tada'
 *   const MyQuery = graphql(`query Foo { ... }`)
 *
 * Disallows:
 *   const MyQuery = `query Foo { ... }`
 *   const MyQuery = "query Foo { ... }"
 */

const GRAPHQL_PATTERN = /^\s*(query|mutation|subscription|fragment)\s/

const message =
  'Raw GraphQL strings are not allowed. Use graphql() from gql.tada for compile-time schema validation. ' +
  'See web/CLAUDE.md for details.'

/** @type {import('eslint').Rule.RuleModule} */
export default {
  meta: {
    type: 'problem',
    docs: {
      description: 'Disallow raw GraphQL query strings; require gql.tada graphql()',
    },
    schema: [],
    messages: {
      noRawGraphQL: message,
    },
  },
  create(context) {
    function isInsideGraphqlCall(node) {
      // Allow: graphql(`query ...`) — the tagged template or call expression from gql.tada
      const parent = node.parent
      if (!parent) return false
      // graphql(`...`) as a call expression argument
      if (
        parent.type === 'CallExpression' &&
        parent.callee.type === 'Identifier' &&
        parent.callee.name === 'graphql'
      ) {
        return true
      }
      return false
    }

    return {
      TemplateLiteral(node) {
        if (isInsideGraphqlCall(node)) return
        // Only check simple template literals (no expressions)
        if (node.expressions.length > 0) return
        const text = node.quasis[0]?.value?.raw ?? ''
        if (GRAPHQL_PATTERN.test(text)) {
          context.report({ node, messageId: 'noRawGraphQL' })
        }
      },
      Literal(node) {
        if (typeof node.value !== 'string') return
        if (GRAPHQL_PATTERN.test(node.value)) {
          context.report({ node, messageId: 'noRawGraphQL' })
        }
      },
    }
  },
}

