/**
 * ESLint rule: no-raw-graphql-strings
 *
 * Prevents raw template-literal or string-literal GraphQL queries.
 * All queries must use graphql() from gql.tada for compile-time schema validation.
 */

const GRAPHQL_PATTERN = /^\s*(query|mutation|subscription|fragment)\s/

const message =
  'Raw GraphQL strings are not allowed. Use graphql() from gql.tada for compile-time schema validation. ' +
  'See web/CLAUDE.md for details.'

/** @type {import('eslint').Rule.RuleModule} */
export default {
  meta: {
    type: 'problem',
    docs: {
      description: 'Disallow raw GraphQL query strings; require gql.tada graphql()',
    },
    schema: [],
    messages: {
      noRawGraphQL: message,
    },
  },
  create(context) {
    function isInsideGraphqlCall(node) {
      const parent = node.parent
      if (!parent) return false
      if (
        parent.type === 'CallExpression' &&
        parent.callee.type === 'Identifier' &&
        parent.callee.name === 'graphql'
      ) {
        return true
      }
      return false
    }

    return {
      TemplateLiteral(node) {
        if (isInsideGraphqlCall(node)) return
        if (node.expressions.length > 0) return
        const text = node.quasis[0]?.value?.raw ?? ''
        if (GRAPHQL_PATTERN.test(text)) {
          context.report({ node, messageId: 'noRawGraphQL' })
        }
      },
      Literal(node) {
        if (typeof node.value !== 'string') return
        if (GRAPHQL_PATTERN.test(node.value)) {
          context.report({ node, messageId: 'noRawGraphQL' })
        }
      },
    }
  },
}

