import { useState } from 'react'
import { Link, useNavigate } from 'react-router-dom'
import {
  Group,
  Burger,
  Drawer,
  Stack,
  Button,
  Text,
  Menu,
  UnstyledButton,
  Avatar,
} from '@mantine/core'
import { useDisclosure } from '@mantine/hooks'
import { Anchor as AnchorIcon, Search, Plus, LogOut, User } from 'lucide-react'
import { useAuthStore } from '@/stores/authStore'

const NAV_LINKS = [
  { label: 'Home', to: '/' },
  { label: 'Search', to: '/search' },
  { label: 'Capture', to: '/capture' },
]

export function Header() {
  const [opened, { toggle, close }] = useDisclosure(false)
  const token = useAuthStore((s) => s.token)
  const user = useAuthStore((s) => s.user)
  const logout = useAuthStore((s) => s.logout)
  const navigate = useNavigate()
  const [userMenuOpened, setUserMenuOpened] = useState(false)

  return (
    <header
      style={{
        position: 'sticky',
        top: 0,
        zIndex: 100,
        backgroundColor: 'var(--mantine-color-brand-6)',
        padding: '0.75rem 1.5rem',
      }}
    >
      <Group justify="space-between">
        <Group gap="xs">
          <AnchorIcon size={24} color="white" />
          <Text
            component={Link}
            to="/"
            fw={700}
            fz="lg"
            c="white"
            style={{ textDecoration: 'none' }}
          >
            Flotsam
          </Text>
        </Group>

        {/* Desktop nav */}
        <Group gap="md" visibleFrom="sm">
          {NAV_LINKS.map((link) => (
            <Text
              key={link.to}
              component={Link}
              to={link.to}
              c="white"
              fz="sm"
              fw={500}
              style={{ textDecoration: 'none' }}
            >
              {link.label}
            </Text>
          ))}

          {token ? (
            <Menu
              opened={userMenuOpened}
              onChange={setUserMenuOpened}
              position="bottom-end"
              withinPortal
            >
              <Menu.Target>
                <UnstyledButton>
                  <Avatar size="sm" radius="xl" color="accent">
                    {user?.displayName?.[0] ?? user?.email?.[0] ?? 'U'}
                  </Avatar>
                </UnstyledButton>
              </Menu.Target>
              <Menu.Dropdown>
                <Menu.Item leftSection={<User size={14} />} disabled>
                  {user?.email ?? 'Account'}
                </Menu.Item>
                <Menu.Divider />
                <Menu.Item leftSection={<LogOut size={14} />} onClick={logout}>
                  Logout
                </Menu.Item>
              </Menu.Dropdown>
            </Menu>
          ) : (
            <Button
              variant="white"
              size="xs"
              onClick={() => navigate('/login')}
            >
              Login
            </Button>
          )}
        </Group>

        {/* Mobile burger */}
        <Burger
          opened={opened}
          onClick={toggle}
          hiddenFrom="sm"
          color="white"
          size="sm"
        />
      </Group>

      {/* Mobile drawer */}
      <Drawer opened={opened} onClose={close} size="xs" title="Menu">
        <Stack gap="md">
          {NAV_LINKS.map((link) => (
            <Text
              key={link.to}
              component={Link}
              to={link.to}
              fz="lg"
              onClick={close}
              style={{ textDecoration: 'none' }}
            >
              {link.label}
            </Text>
          ))}
          {token ? (
            <Button
              variant="subtle"
              leftSection={<LogOut size={16} />}
              onClick={() => {
                logout()
                close()
              }}
            >
              Logout
            </Button>
          ) : (
            <>
              <Button
                leftSection={<Search size={16} />}
                variant="light"
                onClick={() => {
                  navigate('/login')
                  close()
                }}
              >
                Login
              </Button>
              <Button
                leftSection={<Plus size={16} />}
                variant="light"
                onClick={() => {
                  navigate('/register')
                  close()
                }}
              >
                Register
              </Button>
            </>
          )}
        </Stack>
      </Drawer>
    </header>
  )
}

