import { useNavigate } from 'react-router-dom'
import { Container, Title, Text, SimpleGrid, Card, Group, Button, Stack } from '@mantine/core'
import { Search, BookmarkPlus, FileText, Mic } from 'lucide-react'
import { useAuthStore } from '@/stores/authStore'

const FEATURES = [
  {
    icon: BookmarkPlus,
    title: 'Bookmarks',
    description: 'Save URLs with automatic page content extraction and metadata.',
  },
  {
    icon: FileText,
    title: 'Notes',
    description: 'Capture quick text notes with tags and categories.',
  },
  {
    icon: Mic,
    title: 'Voice Notes',
    description: 'Record voice memos with automatic transcription.',
  },
  {
    icon: Search,
    title: 'Semantic Search',
    description: 'Find anything with full-text and AI-powered semantic search.',
  },
]

export function Home() {
  const navigate = useNavigate()
  const token = useAuthStore((s) => s.token)

  return (
    <Container size="md" py="xl">
      <Stack gap="xl">
        <div>
          <Title order={1} c="brand.8">
            Your second brain
          </Title>
          <Text c="dimmed" fz="lg" mt="xs">
            Capture thoughts, bookmarks, and voice notes. Find them instantly with semantic search.
          </Text>
        </div>

        <Group gap="sm">
          <Button
            leftSection={<Search size={16} />}
            onClick={() => navigate('/search')}
          >
            Search
          </Button>
          {token ? (
            <Button
              variant="light"
              leftSection={<BookmarkPlus size={16} />}
              onClick={() => navigate('/capture')}
            >
              Capture
            </Button>
          ) : (
            <Button variant="light" onClick={() => navigate('/login')}>
              Login to capture
            </Button>
          )}
        </Group>

        <SimpleGrid cols={{ base: 1, sm: 2 }} spacing="lg">
          {FEATURES.map((feature) => (
            <Card key={feature.title} shadow="sm" padding="lg" radius="md" withBorder>
              <Group gap="sm" mb="xs">
                <feature.icon size={20} />
