            {result.error.message}
          </Text>
        )}

        {result.data && (
          <Stack gap="sm">
            <Text fz="sm" c="dimmed">
              {result.data.search.total} result{result.data.search.total !== 1 ? 's' : ''}
            </Text>

            {result.data.search.items.map((item) => (
              <Card key={item.id} shadow="xs" padding="md" radius="md" withBorder>
                <Group justify="space-between" mb="xs">
                  <Text fw={600}>{item.title ?? 'Untitled'}</Text>
                  <Badge size="sm" variant="light">
                    {item.type}
                  </Badge>
                </Group>
                {item.contentText && (
                  <Text fz="sm" c="dimmed" lineClamp={2}>
                    {item.contentText}
                  </Text>
                )}
                <Group gap="xs" mt="xs">
                  {item.tags.map((tag) => (
                    <Badge key={tag} size="xs" variant="outline">
                      {tag}
                    </Badge>
                  ))}
                  <Text fz="xs" c="dimmed" ml="auto">
                    {formatDate(item.capturedAt)}
                  </Text>
                </Group>
              </Card>
            ))}
          </Stack>
        )}

        {submitted && !result.fetching && result.data?.search.total === 0 && (
          <Text c="dimmed" ta="center" py="xl">
            No results found.
          </Text>
        )}
      </Stack>
    </Container>
  )
}

